class Solution:
    def minScore(self, n, roads):
        parent = list(range(n + 1))

        def find(x):
            while parent[x] != x:
                parent[x] = parent[parent[x]]
                x = parent[x]
            return x

        def union(a, b):
            ra, rb = find(a), find(b)
            if ra != rb:
                parent[ra] = rb

        for a, b, _ in roads:
            union(a, b)

        target_root = find(1)
        best = float('inf')
        for a, b, w in roads:
            if find(a) == target_root:
                best = min(best, w)
        return best

