from collections import deque

class Solution:
    def minScore(self, n, roads):
        adj = [[] for _ in range(n + 1)]
        for a, b, w in roads:
            adj[a].append((b, w))
            adj[b].append((a, w))
        visited = [False] * (n + 1)
        visited[1] = True
        queue = deque([1])
        best = float('inf')
        while queue:
            city = queue.popleft()
            for nxt, w in adj[city]:
                best = min(best, w)
                if not visited[nxt]:
                    visited[nxt] = True
                    queue.append(nxt)
        return best

