var minScore = function(n, roads) {
    const adj = Array.from({ length: n + 1 }, () => []);
    for (const [a, b, w] of roads) {
        adj[a].push([b, w]);
        adj[b].push([a, w]);
    }
    const visited = new Array(n + 1).fill(false);
    visited[1] = true;
    const queue = [1];
    let head = 0;
    let best = Infinity;
    while (head < queue.length) {
        const city = queue[head++];
        for (const [nxt, w] of adj[city]) {
            if (w < best) best = w;
            if (!visited[nxt]) {
                visited[nxt] = true;
                queue.push(nxt);
            }
        }
    }
    return best;
};
